import React, { useState } from 'react';

interface AuthFormProps {
  onLogin?: () => void;
}

const AuthForm: React.FC<AuthFormProps> = ({ onLogin }) => {
  const [credentials, setCredentials] = useState('');
  const [scope, setScope] = useState('GIGACHAT_API_PERS');
  const [error, setError] = useState('');

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!credentials.trim()) {
      setError('Credentials cannot be empty');
      return;
    }
    console.log('login', { credentials, scope });
    onLogin && onLogin();
  };

  return (
    <form className="auth-form" onSubmit={handleSubmit}>
      <h2>Sign in</h2>
      <label>
        Credentials (Base64):
        <input
          type="password"
          value={credentials}
          onChange={(e) => setCredentials(e.target.value)}
        />
      </label>
      {error && <div className="error-text">{error}</div>}
      <fieldset>
        <legend>Scope</legend>
        <label>
          <input
            type="radio"
            name="scope"
            value="GIGACHAT_API_PERS"
            checked={scope === 'GIGACHAT_API_PERS'}
            onChange={(e) => setScope(e.target.value)}
          />
          Personal
        </label>
        <label>
          <input
            type="radio"
            name="scope"
            value="GIGACHAT_API_B2B"
            checked={scope === 'GIGACHAT_API_B2B'}
            onChange={(e) => setScope(e.target.value)}
          />
          B2B
        </label>
        <label>
          <input
            type="radio"
            name="scope"
            value="GIGACHAT_API_CORP"
            checked={scope === 'GIGACHAT_API_CORP'}
            onChange={(e) => setScope(e.target.value)}
          />
          Corporate
        </label>
      </fieldset>
      <button type="submit">Login</button>
    </form>
  );
};

export default AuthForm;
